# quota/constraint_analysis.py
from dataclasses import dataclass

@dataclass
class IntegrationQuotaDemand:
    peak_rps: float                  # requests per second at peak
    avg_input_tokens_per_request: int
    avg_output_tokens_per_request: int

    @property
    def peak_rpm(self) -> float:
        return self.peak_rps * 60

    @property
    def peak_tpm(self) -> int:
        tokens_per_req = self.avg_input_tokens_per_request + self.avg_output_tokens_per_request
        return int(self.peak_rpm * tokens_per_req)

    def binding_constraint(self, rpm_limit: int, tpm_limit: int) -> str:
        rpm_utilisation = self.peak_rpm / rpm_limit
        tpm_utilisation = self.peak_tpm / tpm_limit
        if rpm_utilisation > tpm_utilisation:
            return f"RPM ({rpm_utilisation:.1%} utilisation)"
        return f"TPM ({tpm_utilisation:.1%} utilisation)"

# Example: RAG support chat
chat = IntegrationQuotaDemand(
    peak_rps=25.0,
    avg_input_tokens_per_request=2200,
    avg_output_tokens_per_request=350,
)
print(f"Peak RPM: {chat.peak_rpm:.0f}")      # 1,500 rpm
print(f"Peak TPM: {chat.peak_tpm:,}")        # 3,825,000 tpm
print(chat.binding_constraint(rpm_limit=5_000, tpm_limit=5_000_000))  # TPM

