from dataclasses import dataclass
import math

@dataclass
class ContextWindowDesign:
    system_prompt_tokens: int       # fixed per request
    retrieved_context_tokens: int   # per RAG retrieval
    conversation_history_tokens: int # per request (amortised)
    user_message_tokens: int        # per request (average)
    output_tokens: int              # per request (average)

    @property
    def total_input_tokens(self) -> int:
        return (
            self.system_prompt_tokens
            + self.retrieved_context_tokens
            + self.conversation_history_tokens
            + self.user_message_tokens
        )

    @property
    def total_tokens_per_request(self) -> int:
        return self.total_input_tokens + self.output_tokens

@dataclass
class UsageModel:
    peak_concurrent_users: int
    avg_requests_per_user_per_minute: float
    daily_active_users: int
    business_hours_per_day: int = 8

    @property
    def peak_rps(self) -> float:
        return (self.peak_concurrent_users * self.avg_requests_per_user_per_minute) / 60

    @property
    def avg_daily_requests(self) -> int:
        avg_rpm = (self.daily_active_users * self.avg_requests_per_user_per_minute)
        return int(avg_rpm * self.business_hours_per_day * 60)

def forecast(design: ContextWindowDesign, usage: UsageModel) -> dict:
    peak_tpm = int(usage.peak_rps * 60 * design.total_tokens_per_request)
    daily_tokens = usage.avg_daily_requests * design.total_tokens_per_request
    monthly_tokens = daily_tokens * 22  # business days

    return {
        "peak_tpm_required": peak_tpm,
        "recommended_tpm_allocation": math.ceil(peak_tpm * 1.3),  # 30% headroom
        "daily_tokens": daily_tokens,
        "monthly_tokens": monthly_tokens,
    }

# Customer support chat integration
design = ContextWindowDesign(
    system_prompt_tokens=800,
    retrieved_context_tokens=3_200,
    conversation_history_tokens=1_500,
    user_message_tokens=200,
    output_tokens=350,
)
usage = UsageModel(
    peak_concurrent_users=200,
    avg_requests_per_user_per_minute=4.0,
    daily_active_users=1_500,
)
result = forecast(design, usage)
print(f"Peak TPM required: {result['peak_tpm_required']:,}")         # 4,760,000
print(f"Recommended allocation: {result['recommended_tpm_allocation']:,}")  # 6,188,000
print(f"Monthly tokens: {result['monthly_tokens']:,}")

# quota/top_down_forecast.py
import statistics
from dataclasses import dataclass
from typing import Sequence

@dataclass
class RequestRecord:
    input_tokens: int
    output_tokens: int
    timestamp_minute: int  # minute-level bucket

def compute_tpm_percentiles(records: Sequence[RequestRecord]) -> dict:
    # Group by minute bucket
    by_minute: dict[int, int] = {}
    for r in records:
        bucket = r.timestamp_minute
        by_minute[bucket] = by_minute.get(bucket, 0) + r.input_tokens + r.output_tokens

    tpm_values = sorted(by_minute.values())
    n = len(tpm_values)
    return {
        "p50_tpm": tpm_values[int(n * 0.50)],
        "p95_tpm": tpm_values[int(n * 0.95)],
        "p99_tpm": tpm_values[int(n * 0.99)],
        "max_tpm": tpm_values[-1],
        "avg_tpm": int(statistics.mean(tpm_values)),
    }

def recommended_quota(percentiles: dict, growth_factor: float = 1.2) -> int:
    # Provision at P99 * growth factor — absorbs current spikes and near-term growth
    return int(percentiles["p99_tpm"] * growth_factor)

# allocation/static_allocator.py
from dataclasses import dataclass

@dataclass
class TeamAllocation:
    team_id: str
    allocated_tpm: int
    review_threshold_pct: float = 0.80  # alert if P95 usage > this fraction

    def is_over_threshold(self, p95_tpm: int) -> bool:
        return p95_tpm > self.allocated_tpm * self.review_threshold_pct

def validate_static_allocation(
    teams: list[TeamAllocation],
    org_total_tpm: int,
    reserve_pct: float = 0.10,
) -> None:
    total_allocated = sum(t.allocated_tpm for t in teams)
    max_allocatable = int(org_total_tpm * (1 - reserve_pct))
    if total_allocated > max_allocatable:
        raise ValueError(
            f"Total allocated {total_allocated:,} exceeds {max_allocatable:,} "
            f"(org quota {org_total_tpm:,} minus {reserve_pct:.0%} reserve)"
        )
    print(f"Allocation valid: {total_allocated:,} / {max_allocatable:,} allocated "
          f"({total_allocated/max_allocatable:.1%})")

# allocation/proportional_rebalancer.py
from dataclasses import dataclass

@dataclass
class TeamUsageData:
    team_id: str
    p95_tpm_last_30d: int
    p99_tpm_last_30d: int
    current_allocation_tpm: int

def rebalance(
    teams: list[TeamUsageData],
    org_total_tpm: int,
    reserve_pct: float = 0.10,
    max_change_pct: float = 0.25,  # no team gains/loses more than 25% per cycle
) -> dict[str, int]:
    allocatable = int(org_total_tpm * (1 - reserve_pct))

    # Target: each team gets allocation = P99 * 1.2, proportionally scaled to fit
    raw_targets = {t.team_id: int(t.p99_tpm_last_30d * 1.2) for t in teams}
    total_raw = sum(raw_targets.values())

    if total_raw == 0:
        return {t.team_id: allocatable // len(teams) for t in teams}

    scale = allocatable / total_raw
    new_allocs = {team_id: int(tpm * scale) for team_id, tpm in raw_targets.items()}

    # Apply change cap
    team_map = {t.team_id: t for t in teams}
    capped = {}
    for team_id, new_tpm in new_allocs.items():
        current = team_map[team_id].current_allocation_tpm
        max_increase = int(current * (1 + max_change_pct))
        max_decrease = int(current * (1 - max_change_pct))
        capped[team_id] = max(max_decrease, min(new_tpm, max_increase))

    return capped

# allocation/burst_pool.py
import time
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class BurstLoan:
    team_id: str
    integration_id: str
    borrowed_tpm: int
    granted_at: float
    max_duration_hours: float = 4.0
    reason: str = ""

    @property
    def expired(self) -> bool:
        return (time.time() - self.granted_at) > (self.max_duration_hours * 3600)

@dataclass
class BurstPool:
    total_tpm: int
    active_loans: list[BurstLoan] = field(default_factory=list)

    @property
    def available_tpm(self) -> int:
        self.active_loans = [l for l in self.active_loans if not l.expired]
        used = sum(l.borrowed_tpm for l in self.active_loans)
        return self.total_tpm - used

    def request_burst(
        self,
        team_id: str,
        integration_id: str,
        requested_tpm: int,
        reason: str,
    ) -> Optional[BurstLoan]:
        if requested_tpm > self.available_tpm:
            return None  # insufficient pool capacity
        loan = BurstLoan(
            team_id=team_id,
            integration_id=integration_id,
            borrowed_tpm=requested_tpm,
            granted_at=time.time(),
            reason=reason,
        )
        self.active_loans.append(loan)
        return loan

# quota/monthly_review.py
from dataclasses import dataclass
from typing import Sequence

@dataclass
class IntegrationQuotaStatus:
    integration_id: str
    team_id: str
    allocated_tpm: int
    p95_tpm_last_30d: int
    p99_tpm_last_30d: int

    @property
    def utilisation_p95(self) -> float:
        return self.p95_tpm_last_30d / self.allocated_tpm if self.allocated_tpm else 0

    @property
    def recommendation(self) -> str:
        u = self.utilisation_p95
        if u > 0.90:
            return "URGENT_INCREASE"
        if u > 0.80:
            return "INCREASE"
        if u < 0.30:
            return "DECREASE"
        return "HOLD"

def run_monthly_review(statuses: Sequence[IntegrationQuotaStatus]) -> None:
    for s in sorted(statuses, key=lambda x: x.utilisation_p95, reverse=True):
        rec = s.recommendation
        if rec != "HOLD":
            print(
                f"{rec:20s}  {s.integration_id:40s}  "
                f"P95 util={s.utilisation_p95:.1%}  "
                f"({s.p95_tpm_last_30d:,} / {s.allocated_tpm:,} TPM)"
            )

# monitoring/quota_alert.py
import logging
from dataclasses import dataclass

@dataclass
class QuotaAlertConfig:
    integration_id: str
    allocated_tpm: int
    warning_threshold_pct: float = 0.70
    critical_threshold_pct: float = 0.85

    @property
    def warning_tpm(self) -> int:
        return int(self.allocated_tpm * self.warning_threshold_pct)

    @property
    def critical_tpm(self) -> int:
        return int(self.allocated_tpm * self.critical_threshold_pct)

def evaluate_quota_alert(config: QuotaAlertConfig, current_tpm: int) -> str:
    if current_tpm >= config.allocated_tpm:
        logging.critical(
            "QUOTA_BREACH %s: %d TPM >= allocation %d",
            config.integration_id, current_tpm, config.allocated_tpm,
        )
        return "EMERGENCY"
    if current_tpm >= config.critical_tpm:
        logging.error(
            "QUOTA_CRITICAL %s: %d TPM (%.1f%% of %d)",
            config.integration_id, current_tpm,
            current_tpm / config.allocated_tpm * 100, config.allocated_tpm,
        )
        return "CRITICAL"
    if current_tpm >= config.warning_tpm:
        logging.warning(
            "QUOTA_WARNING %s: %d TPM (%.1f%% of %d)",
            config.integration_id, current_tpm,
            current_tpm / config.allocated_tpm * 100, config.allocated_tpm,
        )
        return "WARNING"
    return "OK"
